#!/usr/bin/env node
/**
 * Pin/unpin sub-commands as standalone skill shortcuts.
 *
 * Usage:
 *   node <scripts_path>/pin.mjs pin <command>
 *   node <scripts_path>/pin.mjs unpin <command>
 *
 * `pin audit` creates a lightweight /audit skill that redirects to /impeccable audit.
 * `unpin audit` removes that shortcut.
 *
 * The script discovers harness directories (.claude/skills, .cursor/skills, etc.)
 * in the project root and creates/removes the pin in all of them.
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync, rmSync, readdirSync } from 'node:fs';
import { join, resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));

// All known harness directories
const HARNESS_DIRS = [
  '.claude', '.cursor', '.gemini', '.codex', '.agents',
  '.trae', '.trae-cn', '.pi', '.opencode', '.kiro', '.rovodev',
];

// Valid sub-command names
const VALID_COMMANDS = [
  'craft', 'teach', 'extract', 'document', 'shape',
  'critique', 'audit',
  'polish', 'bolder', 'quieter', 'distill', 'harden', 'onboard', 'live',
  'animate', 'colorize', 'typeset', 'layout', 'delight', 'overdrive',
  'clarify', 'adapt', 'optimize',
];

// Marker to identify pinned skills (so unpin doesn't delete user skills)
const PIN_MARKER = '<!-- impeccable-pinned-skill -->';

/**
 * Walk up from startDir to find a project root.
 */
function findProjectRoot(startDir = process.cwd()) {
  let dir = resolve(startDir);
  while (dir !== '/') {
    if (
      existsSync(join(dir, 'package.json')) ||
      existsSync(join(dir, '.git')) ||
      existsSync(join(dir, 'skills-lock.json'))
    ) {
      return dir;
    }
    const parent = resolve(dir, '..');
    if (parent === dir) break;
    dir = parent;
  }
  return resolve(startDir);
}

/**
 * Find harness skill directories that have an impeccable skill installed.
 */
function findHarnessDirs(projectRoot) {
  const dirs = [];
  for (const harness of HARNESS_DIRS) {
    const skillsDir = join(projectRoot, harness, 'skills');
    // Only pin in harness dirs that already have impeccable installed
    const impeccableDir = join(skillsDir, 'impeccable');
    if (existsSync(impeccableDir) || existsSync(join(skillsDir, 'i-impeccable'))) {
      dirs.push(skillsDir);
    }
  }
  return dirs;
}

/**
 * Load command metadata (descriptions for pinned skills).
 */
function loadCommandMetadata() {
  const metadataPath = join(__dirname, 'command-metadata.json');
  if (existsSync(metadataPath)) {
    return JSON.parse(readFileSync(metadataPath, 'utf-8'));
  }
  return {};
}

/**
 * Generate a pinned skill's SKILL.md content.
 */
function generatePinnedSkill(command, metadata) {
  const desc = metadata[command]?.description || `Shortcut for /impeccable ${command}.`;
  const hint = metadata[command]?.argumentHint || '[target]';

  return `---
name: ${command}
description: "${desc}"
argument-hint: "${hint}"
user-invocable: true
---

${PIN_MARKER}

This is a pinned shortcut for \`{{command_prefix}}impeccable ${command}\`.

Invoke {{command_prefix}}impeccable ${command}, passing along any arguments provided here, and follow its instructions.
`;
}

/**
 * Pin a command: create shortcut skill in all harness dirs.
 */
function pin(command, projectRoot) {
  const metadata = loadCommandMetadata();
  const harnessDirs = findHarnessDirs(projectRoot);

  if (harnessDirs.length === 0) {
    console.log('No harness directories with impeccable installed found.');
    return false;
  }

  const content = generatePinnedSkill(command, metadata);
  let created = 0;

  for (const skillsDir of harnessDirs) {
    // Check if skill already exists (and isn't a pin)
    const skillDir = join(skillsDir, command);
    if (existsSync(skillDir)) {
      const existingMd = join(skillDir, 'SKILL.md');
      if (existsSync(existingMd)) {
        const existing = readFileSync(existingMd, 'utf-8');
        if (!existing.includes(PIN_MARKER)) {
          console.log(`  SKIP: ${skillDir} (non-pinned skill already exists)`);
          continue;
        }
      }
    }

    mkdirSync(skillDir, { recursive: true });
    writeFileSync(join(skillDir, 'SKILL.md'), content, 'utf-8');
    console.log(`  + ${skillDir}`);
    created++;
  }

  if (created > 0) {
    console.log(`\nPinned '${command}' as a standalone shortcut in ${created} location(s).`);
    console.log(`You can now use /${command} directly.`);
  }

  return created > 0;
}

/**
 * Unpin a command: remove shortcut skill from all harness dirs.
 */
function unpin(command, projectRoot) {
  const harnessDirs = findHarnessDirs(projectRoot);
  let removed = 0;

  for (const skillsDir of harnessDirs) {
    const skillDir = join(skillsDir, command);
    if (!existsSync(skillDir)) continue;

    const skillMd = join(skillDir, 'SKILL.md');
    if (!existsSync(skillMd)) continue;

    // Safety: only remove if it's a pinned skill
    const content = readFileSync(skillMd, 'utf-8');
    if (!content.includes(PIN_MARKER)) {
      console.log(`  SKIP: ${skillDir} (not a pinned skill)`);
      continue;
    }

    rmSync(skillDir, { recursive: true, force: true });
    console.log(`  - ${skillDir}`);
    removed++;
  }

  if (removed > 0) {
    console.log(`\nUnpinned '${command}' from ${removed} location(s).`);
    console.log(`Use /impeccable ${command} to access it.`);
  } else {
    console.log(`No pinned '${command}' shortcut found.`);
  }

  return removed > 0;
}

// --- CLI ---
const [,, action, command] = process.argv;

if (!action || !command) {
  console.log('Usage: node pin.mjs <pin|unpin> <command>');
  console.log(`\nAvailable commands: ${VALID_COMMANDS.join(', ')}`);
  process.exit(1);
}

if (action !== 'pin' && action !== 'unpin') {
  console.error(`Unknown action: ${action}. Use 'pin' or 'unpin'.`);
  process.exit(1);
}

if (!VALID_COMMANDS.includes(command)) {
  console.error(`Unknown command: ${command}`);
  console.error(`Available commands: ${VALID_COMMANDS.join(', ')}`);
  process.exit(1);
}

const root = findProjectRoot();

if (action === 'pin') {
  pin(command, root);
} else {
  unpin(command, root);
}

import { describe, expect, it } from "vitest";
import {
  isDelegationActive,
  loadDelegationCredential,
} from "./delegation.js";
import {
  mintDelegationCredentialBody,
  mintAndSignDelegationCredential,
} from "@ghostbroker/agent-client";
import { mkdtempSync, rmSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";
import { secp256k1 } from "@noble/curves/secp256k1.js";
import { keccak_256 } from "@noble/hashes/sha3.js";
import type { DelegationCredential } from "@ghostbroker/agent-client";

/**
 * Tests for the agents workspace delegation helpers.
 *
 * The signing logic (canonical-JSON, EIP-191, ECDSA
 * secp256k1) is covered exhaustively in
 * `agent-client/src/delegation-signer.test.ts`. This file
 * focuses on:
 *   - the `delegationSchema` zod validation via `loadDelegationCredential`,
 *   - the `isDelegationActive` time-window helper,
 *   - writing VCs to disk and loading them back.
 *
 * Post-Phase 1: the disk-writing wrappers (`mintDelegationCredential`,
 * `mintAndSignDelegationCredential`) were removed from `delegation.ts`.
 * Tests that need an on-disk VC now use the canonical functions from
 * `@ghostbroker/agent-client` directly.
 */

describe("delegation credential loading / validation", () => {
  const tmp = mkdtempSync(join(tmpdir(), "ghostbroker-delegation-test-"));

  it("loads a VC written via mintDelegationCredentialBody through the zod schema", () => {
    const body = mintDelegationCredentialBody({
      issuerDid: "did:t3n:0x0000000000000000000000000000000000000001",
      agentDid: "did:t3n:0xagent",
      maxSpendUsd: 1_000,
      purpose: "test",
    });
    const path = join(tmp, "roundtrip.json");
    writeFileSync(path, JSON.stringify(body, null, 2), "utf8");
    const loaded = loadDelegationCredential(path);
    expect(loaded.credentialSubject.agentDid).toBe("did:t3n:0xagent");
    expect(loaded.credentialSubject.maxSpendUsd).toBe(1_000);
    expect(loaded.id).toMatch(/^urn:uuid:ghostbroker-delegation-/);
  });

  it("rejects an unknown purchase category", () => {
    const badPath = join(tmp, "bad.json");
    writeFileSync(
      badPath,
      JSON.stringify({
        id: "urn:uuid:bad",
        type: ["VerifiableCredential", "GhostBrokerDelegation"],
        issuer: "did:t3n:0x0000000000000000000000000000000000000001",
        issuanceDate: "2026-01-01T00:00:00Z",
        expirationDate: "2027-01-01T00:00:00Z",
        credentialSubject: {
          id: "did:t3n:0x0000000000000000000000000000000000000001",
          agentDid: "did:t3n:0xagent",
          maxSpendUsd: 1_000,
          allowedCategories: ["weapons"], // not in the enum
          purpose: "test",
        },
      }),
      "utf8",
    );
    expect(() => loadDelegationCredential(badPath)).toThrow();
  });

  it("isDelegationActive is true within the window and false outside", () => {
    const body = mintDelegationCredentialBody({
      issuerDid: "did:t3n:0x0000000000000000000000000000000000000001",
      agentDid: "did:t3n:0xagent",
      maxSpendUsd: 1_000,
      purpose: "test",
    });
    const path = join(tmp, "active.json");
    writeFileSync(path, JSON.stringify(body, null, 2), "utf8");
    const loaded = loadDelegationCredential(path);
    expect(isDelegationActive(loaded, new Date())).toBe(true);
    expect(isDelegationActive(loaded, new Date("2020-01-01T00:00:00Z"))).toBe(false);
  });

  // Cleanup
  it("cleanup tmp dir", () => {
    rmSync(tmp, { recursive: true, force: true });
    expect(true).toBe(true);
  });
});

describe("signed VC round-trip via @ghostbroker/agent-client", () => {
  const tmp = mkdtempSync(join(tmpdir(), "ghostbroker-sign-test-"));

  it("writes a real signed VC to disk that round-trips through the schema", () => {
    const seed = keccak_256(
      new TextEncoder().encode("ghostbroker-agents-test-v1"),
    );
    const privKey = `0x${Buffer.from(seed).toString("hex")}` as `0x${string}`;
    const pubKey = `0x${Buffer.from(secp256k1.getPublicKey(seed, true)).toString("hex")}` as `0x${string}`;

    const outPath = join(tmp, "signed.json");
    const vc = mintAndSignDelegationCredential({
      agentDid: "did:t3n:0xagent",
      maxSpendUsd: 2_500,
      issuerPrivateKey: privKey,
      issuerPublicKey: pubKey,
      issuerDid: "did:t3n:0xagent",
    });
    writeFileSync(outPath, JSON.stringify(vc, null, 2), "utf8");
    expect(vc.proof?.type).toBe("EcdsaSecp256k1Signature2019");
    expect(vc.proof?.jws).toMatch(/^0x[0-9a-f]{130}$/);

    const loaded = loadDelegationCredential(outPath);
    expect(loaded.proof?.type).toBe("EcdsaSecp256k1Signature2019");
  });

  // Cleanup
  it("cleanup tmp dir", () => {
    rmSync(tmp, { recursive: true, force: true });
    expect(true).toBe(true);
  });
});

#!/usr/bin/env node
// One-shot dedup: when the patch script ran twice,
// some files have two `configureAgent: ...` keys
// back-to-back. The second key is syntactically at the
// wrong indent. Detect the broken pattern and emit a
// single correctly-indented key.

import { readFileSync, writeFileSync, readdirSync, statSync } from "node:fs";
import { join } from "node:path";

const TARGETS = ["src/tests/contracts", "src/tests/integration", "src/tests/unit"];

function walk(dir, out = []) {
  for (const entry of readdirSync(dir)) {
    const p = join(dir, entry);
    if (statSync(p).isDirectory()) {
      walk(p, out);
    } else if (p.endsWith(".ts")) {
      out.push(p);
    }
  }
  return out;
}

const BROKEN = /(loadDelegationCredential: async \(\) => null,)\s*\n(\s+)configureAgent: async \(\) => \{ throw new Error\("not used"\); \},\s*\n(\s+)([a-zA-Z]+:) /g;

let patched = 0;
for (const dir of TARGETS) {
  for (const file of walk(dir)) {
    const t = readFileSync(file, "utf8");
    // First collapse the broken fragment: a
    // `loadDelegationCredential` line followed by a
    // mis-indented `configureAgent` followed by a
    // normally-indented key. Replace the whole
    // 3-line fragment with a clean 3-line block.
    const out = t.replace(
      BROKEN,
      (_match, ldcLine, badIndent, goodIndent, nextKey) => {
        return `${ldcLine}\n${goodIndent}configureAgent: async () => {\n${goodIndent}  throw new Error("not used");\n${goodIndent}},\n${goodIndent}${nextKey} `;
      },
    );
    if (out !== t) {
      writeFileSync(file, out, "utf8");
      patched += 1;
      console.log(`patched ${file}`);
    }
  }
}
console.log(`total: ${patched}`);

