import { Router } from "express";
import { z } from "zod";
import { assertInstitutionScope, requireOperatorAuth } from "../auth/operator-auth.js";
import { PublicError } from "../errors/public-error.js";
import type { ApiKeyManagementService } from "../services/api-key.service.js";
import type {
  DemoAgentOrchestrator,
  DemoStatus,
} from "../services/demo-orchestrator.js";
import type { AgentManagementService } from "../services/agent.service.js";
import type { TenantDelegationSigner } from "../services/tenant-delegation-signer.js";

/**
 * Demo Mode HTTP surface.
 *
 * The dashboard's Observatory tab calls these three
 * endpoints to drive the one-click "Spin up demo agents"
 * flow:
 *
 *   - `POST /api/demo/start` — mints a per-institution
 *     demo API key (via the existing `apiKeyService`),
 *     configures buyer + seller agent records with server-
 *     minted delegation VCs, and spawns the buyer + seller
 *     agent child processes with the pre-configured DIDs.
 *     Returns the running status (PIDs, startedAt).
 *   - `POST /api/demo/stop`  — kills both children and
 *     revokes the demo API key. Idempotent: a stop with
 *     nothing running is a 200 with `running: false`.
 *   - `GET  /api/demo/status` — current state, including
 *     the most recent stdout/stderr tail from each
 *     child (the UI shows a "view logs" affordance on
 *     hover).
 *
 * All three are operator-scoped. The start route asserts
 * the operator's session matches the institution the demo
 * runs under — the dashboard's session is the authority
 * here, and the demo API key is scoped to the same
 * institution.
 *
 * Wiring lives in `app.ts` (mount) and `BackendServices`
 * (the orchestrator bag).
 */
export function createDemoRouter(options: {
  orchestrator: DemoAgentOrchestrator;
  apiKeyService: ApiKeyManagementService;
  agentService: AgentManagementService;
  tenantSigner?: TenantDelegationSigner;
}): Router {
  const router = Router();
  const { orchestrator, apiKeyService, agentService, tenantSigner } = options;

  const startSchema = z.object({
    institutionId: z.string().uuid(),
  });

  router.post("/demo/start", async (request, response, next) => {
    try {
      const operatorAuth = requireOperatorAuth(response);

      const parsed = startSchema.safeParse(request.body);
      if (!parsed.success) {
        throw new PublicError("validation_failed", 400, parsed.error);
      }
      assertInstitutionScope(operatorAuth, parsed.data.institutionId);

      // The demo API key is a fresh key minted for the
      // demo run. We mint it through the same service the
      // dashboard uses, so the audit log + label match
      // production keys. The key is short-lived: the
      // orchestrator revokes it on stop; a backend
      // crash leaves the key in the DB but the demo is
      // already gone (no spawned child to use it), and
      // the operator can sweep via the API Keys panel.
      const apiKey = await apiKeyService.createKey(
        parsed.data.institutionId,
        `demo-${new Date().toISOString().slice(11, 19)}`,
        ["agent:operate"],
      );

      try {
        // The tenant signer is required to mint delegation
        // VCs for the demo agents. If the backend was started
        // without a T3N key (e.g. some test compositions), the
        // signer is absent and the start endpoint returns 503.
        if (!tenantSigner) {
          throw new PublicError("service_unavailable", 503);
        }

        // Before spawning agents, configure them with server-
        // minted delegation VCs. The DIDs are generated by
        // the backend (`configureAgent` mints a synthetic
        // `did:t3n:demo-<random>` when no explicit DID is
        // given) and passed to the spawned processes via
        // `AGENT_IDENTITY_DID` so the agent uses the same
        // DID on admit. This is the Phase 2.5 / Phase 1
        // step 4 entrypoint: "Configure Agent" → "Admit".
        // The `mint()` validates input via Zod, so we
        // bridge the ReadonlyArray → Array gap via `as any`.
        const buyerAgent = await agentService.configureAgent({
          institutionId: parsed.data.institutionId,
          label: "Demo Buyer",
          policy: {
            maxSpendUsd: 10_000,
            allowedCategories: ["services"],
            purpose: "demo buyer",
            validityMonths: 1,
          },
          signCredential: async (input) => tenantSigner.mint(input as any),
        });
        const sellerAgent = await agentService.configureAgent({
          institutionId: parsed.data.institutionId,
          label: "Demo Seller",
          policy: {
            maxSpendUsd: 10_000,
            allowedCategories: ["services"],
            purpose: "demo seller",
            validityMonths: 1,
          },
          signCredential: async (input) => tenantSigner.mint(input as any),
        });

        const status = await orchestrator.startDemo({
          institutionId: parsed.data.institutionId,
          demoApiKey: apiKey.key,
          apiKeyId: apiKey.id,
          buyerAgentDid: buyerAgent.agent.agentDid,
          sellerAgentDid: sellerAgent.agent.agentDid,
        });
        response.status(200).json(status);
      } catch (err) {
        // If the orchestrator refused to start (e.g. one
        // already running), roll back the freshly-minted
        // key so we don't leak an unused bearer.
        try {
          await apiKeyService.revokeKey(apiKey.id, parsed.data.institutionId);
        } catch {
          // best-effort
        }
        throw err;
      }
    } catch (error) {
      next(error);
    }
  });

  router.post("/demo/stop", async (_request, response, next) => {
    try {
      const status: DemoStatus = await orchestrator.stopDemo();
      response.status(200).json(status);
    } catch (error) {
      next(error);
    }
  });

  router.get("/demo/status", async (_request, response, next) => {
    try {
      const status: DemoStatus = orchestrator.getStatus();
      response.status(200).json(status);
    } catch (error) {
      next(error);
    }
  });

  return router;
}

import { Router, type RequestHandler } from "express";
import { assertInstitutionScope, requireOperatorAuth } from "../auth/operator-auth.js";
import { PublicError } from "../errors/public-error.js";
import { createInstitutionRequestSchema } from "../models/institution.js";
import type { InstitutionManagementService } from "../services/institution.service.js";

export function createInstitutionsRouter(
  institutionService: InstitutionManagementService,
  authMiddleware: RequestHandler,
): Router {
  const router = Router();

  router.post("/institutions", async (request, response, next) => {
    try {
      const parsed = createInstitutionRequestSchema.safeParse(request.body);

      if (!parsed.success) {
        throw new PublicError("validation_failed", 400, parsed.error);
      }

      const institution = await institutionService.createInstitution(parsed.data);
      response.status(201).json({
        id: institution.id,
        legalName: institution.legalName,
        displayName: institution.displayName,
        status: institution.status,
        t3TenantDid: institution.t3TenantDid,
      });
    } catch (error) {
      next(error);
    }
  });

  router.get("/institutions/:id", authMiddleware, async (request, response, next) => {
    try {
      const operatorAuth = requireOperatorAuth(response);
      const id = request.params.id as string;
      assertInstitutionScope(operatorAuth, id);

      const institution = await institutionService.getInstitution!(id);
      response.status(200).json(institution);
    } catch (error) {
      next(error);
    }
  });

  router.post("/institutions/:id/rotate-key", authMiddleware, async (request, response, next) => {
    try {
      const operatorAuth = requireOperatorAuth(response);
      const id = request.params.id as string;
      assertInstitutionScope(operatorAuth, id);

      const institution = await institutionService.rotateKeys!(id);
      response.status(200).json(institution);
    } catch (error) {
      next(error);
    }
  });

  return router;
}

