import { PublicError } from "../errors/public-error.js";
import { randomBytes } from "node:crypto";
import type { AgentAuthorizationFacade } from "../auth/agent-authz.js";
import type {
  AdmitAgentRequest,
  AgentAdmission,
  Agent,
  AgentStatus,
  DirectionScope,
} from "../models/agent.js";
import type { AgentRepository } from "./agent-repository.js";
import {
  EmptyAuthorityRevocationRepository,
  type AuthorityRevocationRepository,
} from "./authority-revocation.service.js";
import type { MatchingOrchestrator } from "./matching-orchestrator.js";
import type { DelegationCredential } from "@ghostbroker/agent-client";

export interface AgentAdmissionService {
  admitAgent(request: AdmitAgentRequest): Promise<AgentAdmission>;
}

export interface AgentManagementService extends AgentAdmissionService {
  listAgents(
    institutionId: string,
    status?: AgentStatus,
  ): Promise<Agent[]>;
  getAgent(id: string, institutionId: string): Promise<Agent>;
  updateAgentLabel(id: string, institutionId: string, label: string): Promise<Agent>;
  revokeAgent(id: string, institutionId: string): Promise<void>;
  /**
   * Persist a freshly-signed delegation VC on the agent's
   * `metadata.delegation_credential` column. The
   * `authorityRef` stored on the agent record is also updated
   * so future `loadAndVerify` calls return the right id.
   * Returns the updated agent record.
   */
  persistDelegation(input: {
    agentId: string;
    institutionId: string;
    credential: DelegationCredential;
    policyHash: string;
  }): Promise<Agent>;
  /**
   * Look up the persisted delegation VC for an agent. Returns
   * `null` when the agent has no VC yet (e.g. a freshly-created
   * agent record pre-admit). The facade uses this on every
   * privileged call so the agent never has to send the VC.
   */
  loadDelegationCredential(input: {
    agentId: string;
    institutionId: string;
  }): Promise<DelegationCredential | null>;
  /**
   * Phase 1 step 4 + Phase 2.5: the "Configure Agent"
   * entrypoint. Mints a fresh agent DID (or accepts one
   * from the dashboard), signs a tenant VC for the
   * policy the dashboard collected, and persists the
   * agent record with the VC in metadata. The agent
   * process later calls `POST /api/agents/admit` with
   * the same `agentDid`; the backend's `loadAndVerify`
   * facade looks the VC up by `agentId` and re-verifies
   * on every privileged call.
   *
   * Returns the new agent record and the policy hash
   * the verifier will produce.
   */
  configureAgent(input: {
    institutionId: string;
    agentDid?: string;
    label?: string;
    policy: {
      maxSpendUsd: number;
      allowedCategories: ReadonlyArray<
        "office-supplies" | "software" | "hardware" | "services" | "travel"
      >;
      approverEmail?: string;
      purpose?: string;
      validityMonths?: number;
    };
    /**
     * Callback that signs the VC. The backend owns the
     * tenant signer; tests inject a stub. Keeps the
     * `tenant-delegation-signer` import out of the
     * service's transitive dependency surface.
     */
    signCredential: (input: {
      agentDid: string;
      institutionId: string;
      maxSpendUsd: number;
      allowedCategories: ReadonlyArray<
        "office-supplies" | "software" | "hardware" | "services" | "travel"
      >;
      approverEmail?: string;
      purpose?: string;
      validityMonths?: number;
    }) => Promise<{ credential: DelegationCredential; policyHash: string }>;
  }): Promise<{ agent: Agent; policyHash: string }>;
}

export class AgentService implements AgentManagementService {
  private readonly authorization: AgentAuthorizationFacade;
  private readonly revocations: AuthorityRevocationRepository;
  private readonly repository: AgentRepository;
  private readonly matchingOrchestrator: MatchingOrchestrator | undefined;

  public constructor(
    authorization: AgentAuthorizationFacade,
    repository: AgentRepository,
    revocations: AuthorityRevocationRepository = new EmptyAuthorityRevocationRepository(),
    matchingOrchestrator?: MatchingOrchestrator,
  ) {
    this.authorization = authorization;
    this.repository = repository;
    this.revocations = revocations;
    this.matchingOrchestrator = matchingOrchestrator;
  }

  public async admitAgent(request: AdmitAgentRequest): Promise<AgentAdmission> {
    console.log("[ADMIT.SERVICE] admitAgent called, delegationCredential:", request.delegationCredential === undefined ? "absent" : "present");
    const revokedAuthorityRefs =
      await this.revocations.listRevokedAuthorityRefs(
        request.institutionId,
        request.agentDid,
      );

    // Ghostbroker-only path. The JCS Smart-VC verifier is gone —
    // the live T3N onboarding surface only issues Ghostbroker-style
    // W3C credentials. The credential is persisted on the agent
    // record so submit / cancel / settlement can re-verify it.
    //
    // Post-Phase 1: the agent process no longer sends the
    // delegation VC inline (the backend owns it). When the
    // request does not carry a VC, we look up the agent record
    // by DID and load the persisted credential. This supports
    // both the dashboard's "Configure Agent" → "Admit" flow
    // and the Phase 2.5 demo orchestrator (which configures
    // agents before spawning the child processes).
    let delegationCredential = request.delegationCredential;
    if (!delegationCredential) {
      const existingAgent = await this.repository.findByAgentDid(
        request.institutionId,
        request.agentDid,
      );
      if (existingAgent) {
        const persistedVc = (
          existingAgent.metadata as Record<string, unknown> | null
        )?.delegation_credential;
        if (persistedVc) {
          delegationCredential = persistedVc;
        }
      }
    }

    // When delegationCredential is still undefined (no inline VC,
    // no persisted VC — e.g. direct agent run without the demo
    // orchestrator or the dashboard Configure Agent flow), fall
    // back to a sandbox admit in development mode. The agent is
    // already authenticated via API key and scoped to the
    // institution; the sandbox authority ref lets the admit
    // complete so the agent can submit intents. In live mode
    // this path rejects with 403.
    if (!delegationCredential) {
      return this.sandboxAdmit({
        request,
      });
    }

    const verification = await this.authorization.verifyAgentAuthority({
      institutionId: request.institutionId,
      agentDid: request.agentDid,
      authorityRef: "",
      delegationCredential,
      requestedAction: "agent.admit",
      revokedAuthorityRefs,
    });

    if (verification.status !== "verified") {
      throw new PublicError("authorization_failed", 403);
    }

    // Check if the agent record already exists (loaded from the
    // VC lookup above). If so, return the existing admission
    // rather than attempting a duplicate insert — the agents
    // table has a unique constraint on (institution_id, agent_did).
    const alreadyAdmitted = await this.repository.findByAgentDid(
      request.institutionId,
      request.agentDid,
    );
    if (alreadyAdmitted) {
      return {
        id: alreadyAdmitted.id,
        agentDid: alreadyAdmitted.agentDid,
        status: "admitted",
        authorityRef: alreadyAdmitted.authorityRef,
      };
    }

    return this.persistAdmittedAgent({
      request,
      authorityRef: verification.authorityRef,
      policyHash: verification.policyHash,
      delegationCredential,
    });
  }

  /**
   * Shared persistence path for the admit flow. Writes the agent
   * record (with the Ghostbroker delegation VC stored in `metadata`) and
   * returns the public `AgentAdmission` shape.
   */
  /**
   * Sandbox admit path for agents that run without a delegation
   * VC (e.g. direct `npm run buyer` without the demo orchestrator
   * or dashboard Configure Agent flow). Generates a synthetic
   * authority ref and admits the agent so it can submit intents.
   *
   * This is safe because the agent is already authenticated via
   * API key (scoped to a specific institution). The sandbox mode
   * is the default when `VC_VERIFY_MODE` is not set to `live`.
   * In live production, this path throws 403 to enforce the
   * delegation VC requirement.
   */
  private async sandboxAdmit(input: {
    request: AdmitAgentRequest;
  }): Promise<AgentAdmission> {
    const { request } = input;

    // Only allow sandbox admit in non-live environments. The
    // mode is read from the env var (same convention as
    // `verifyGhostbrokerDelegationCredential`).
    const mode = (process.env.VC_VERIFY_MODE ?? "sandbox").trim().toLowerCase();
    if (mode === "live") {
      throw new PublicError("authorization_failed", 403);
    }

    // Check if the agent already exists (e.g. a previous
    // sandbox admit created the record). The agents table has
    // a unique constraint on (institution_id, agent_did), so
    // we must return the existing admission rather than
    // attempting a duplicate insert.
    const existing = await this.repository.findByAgentDid(
      request.institutionId,
      request.agentDid,
    );
    console.log(
      "[SANDBOX]",
      "did:", request.agentDid.slice(0, 30),
      "existing:", existing ? existing.id : "null",
    );
    if (existing) {
      return {
        id: existing.id,
        agentDid: existing.agentDid,
        status: "admitted",
        authorityRef: existing.authorityRef,
      };
    }

    const agent = await this.repository.create({
      institutionId: request.institutionId,
      agentDid: request.agentDid,
      authorityRef: `ghostbroker-delegation:sandbox-admit-${cryptoRandomHex(16)}`,
      instrumentScope: request.limits?.instrumentScope ?? null,
      directionScope: request.limits?.directionScope ?? null,
      maxNotional: request.limits?.maxNotional ?? null,
      limitReference: request.limits?.limitReference ?? null,
      policyHash: cryptoRandomHex(32),
    });

    return {
      id: agent.id,
      agentDid: agent.agentDid,
      status: "admitted",
      authorityRef: agent.authorityRef,
    };
  }

  private async persistAdmittedAgent(input: {
    request: AdmitAgentRequest;
    authorityRef: string;
    policyHash: string;
    delegationCredential?: unknown;
  }): Promise<AgentAdmission> {
    const { request, authorityRef, policyHash, delegationCredential } = input;
    const agent = await this.repository.create({
      institutionId: request.institutionId,
      agentDid: request.agentDid,
      authorityRef,
      instrumentScope: request.limits?.instrumentScope ?? null,
      directionScope: request.limits?.directionScope ?? null,
      maxNotional: request.limits?.maxNotional ?? null,
      limitReference: request.limits?.limitReference ?? null,
      policyHash,
      delegationCredential,
    });

    return {
      id: agent.id,
      agentDid: agent.agentDid,
      status: "admitted",
      authorityRef: agent.authorityRef,
      ...(agent.instrumentScope
        ? {
            limits: {
              instrumentScope: agent.instrumentScope,
              directionScope: (agent.directionScope ?? ["buy", "sell"]) as DirectionScope[],
              maxNotional: agent.maxNotional ?? "0",
              limitReference: agent.limitReference ?? "",
              policyHash: agent.policyHash ?? "",
            },
          }
        : {}),
    };
  }

  public async listAgents(
    institutionId: string,
    status?: AgentStatus,
  ): Promise<Agent[]> {
    return this.repository.listByInstitution(institutionId, status);
  }

  public async getAgent(
    id: string,
    institutionId: string,
  ): Promise<Agent> {
    const agent = await this.repository.findById(id, institutionId);
    if (!agent) {
      throw new PublicError("not_found", 404);
    }
    return agent;
  }

  public async updateAgentLabel(
    id: string,
    institutionId: string,
    label: string,
  ): Promise<Agent> {
    const agent = await this.repository.findById(id, institutionId);
    if (!agent) {
      throw new PublicError("not_found", 404);
    }
    await this.repository.updateLabel(id, label);
    return { ...agent, label };
  }

  public async revokeAgent(id: string, institutionId: string): Promise<void> {
    // Find the agent to get its agentDid for cascade operations
    const agents = await this.repository.listByInstitution(institutionId);
    const agent = agents.find((a) => a.id === id);

    if (!agent) {
      throw new PublicError("not_found", 404);
    }

    // Revoke in the database
    await this.repository.revoke(id);

    // Cascade: clear any pending intents from the matching orchestrator
    if (this.matchingOrchestrator) {
      this.matchingOrchestrator.removeIntentsByAgent(agent.agentDid, institutionId);
    }
  }

  public async persistDelegation(input: {
    agentId: string;
    institutionId: string;
    credential: DelegationCredential;
    policyHash: string;
  }): Promise<Agent> {
    const existing = await this.repository.findById(
      input.agentId,
      input.institutionId,
    );
    if (!existing) {
      throw new PublicError("not_found", 404);
    }
    // Two writes: metadata (the VC) and authority_ref (the
    // verifier's authorityRef). Both are needed because the
    // verifier computes authorityRef from `credential.id`,
    // and the agent record's `authority_ref` column is the
    // public-facing id the agent process echoes back.
    const authorityRef = `ghostbroker-delegation:${input.credential.id}`;
    const withMeta = await this.repository.updateMetadata(input.agentId, {
      delegation_credential: input.credential,
    });
    return this.repository.updateAuthorityRef({
      id: input.agentId,
      authorityRef,
      policyHash: input.policyHash,
    }).then((updated) => updated ?? withMeta);
  }

  public async loadDelegationCredential(input: {
    agentId: string;
    institutionId: string;
  }): Promise<DelegationCredential | null> {
    const agent = await this.repository.findById(
      input.agentId,
      input.institutionId,
    );
    if (!agent) {
      return null;
    }
    const vc = (agent.metadata as Record<string, unknown> | null)
      ?.delegation_credential;
    if (vc && typeof vc === "object") {
      return vc as DelegationCredential;
    }
    return null;
  }

  public async configureAgent(input: {
    institutionId: string;
    agentDid?: string;
    label?: string;
    policy: {
      maxSpendUsd: number;
      allowedCategories: ReadonlyArray<
        "office-supplies" | "software" | "hardware" | "services" | "travel"
      >;
      approverEmail?: string;
      purpose?: string;
      validityMonths?: number;
    };
    signCredential: (input: {
      agentDid: string;
      institutionId: string;
      maxSpendUsd: number;
      allowedCategories: ReadonlyArray<
        "office-supplies" | "software" | "hardware" | "services" | "travel"
      >;
      approverEmail?: string;
      purpose?: string;
      validityMonths?: number;
    }) => Promise<{ credential: DelegationCredential; policyHash: string }>;
  }): Promise<{ agent: Agent; policyHash: string }> {
    // The agent DID is either the one the dashboard
    // minted client-side, or a synthetic
    // `did:t3n:demo-<random>` placeholder minted by the
    // backend for the demo orchestrator path. The agent
    // process re-uses this exact DID on its admit call.
    const agentDid =
      input.agentDid ?? `did:t3n:demo-${cryptoRandomHex(24)}`;

    const { credential, policyHash } = await input.signCredential({
      agentDid,
      institutionId: input.institutionId,
      maxSpendUsd: input.policy.maxSpendUsd,
      allowedCategories: input.policy.allowedCategories,
      ...(input.policy.approverEmail
        ? { approverEmail: input.policy.approverEmail }
        : {}),
      ...(input.policy.purpose ? { purpose: input.policy.purpose } : {}),
      ...(input.policy.validityMonths
        ? { validityMonths: input.policy.validityMonths }
        : {}),
    });

    const authorityRef = `ghostbroker-delegation:${credential.id}`;
    const agent = await this.repository.create({
      institutionId: input.institutionId,
      agentDid,
      authorityRef,
      label: input.label ?? null,
      policyHash,
      delegationCredential: credential,
    });

    return { agent, policyHash };
  }
}

/**
 * Generate a short random hex string. The T3N DID
 * convention is `did:t3n:<identifier>`; for the demo
 * orchestrator path we mint a synthetic identifier
 * derived from `randomBytes(12)` (24 hex chars). 48
 * bits of entropy is enough to disambiguate concurrent
 * demo runs on the same institution.
 */
function cryptoRandomHex(byteLength: number): string {
  return randomBytes(byteLength).toString("hex");
}

import { spawn, type ChildProcess } from "node:child_process";
import { resolve } from "node:path";
import type { ApiKeyManagementService } from "./api-key.service.js";
import { PublicError } from "../errors/public-error.js";

/**
 * Owns the lifecycle of the Phase 2.5 demo agent child
 * processes.
 *
 * When the operator clicks "Spin up demo agents" on the
 * Observatory tab, the backend:
 *
 *   1. Mints a short-TTL per-institution API key via the
 *      existing `apiKeyService` (the key is scoped to one
 *      institution, has a 1-hour TTL by convention, and
 *      is revoked when the demo stops — see the route
 *      handler for the TTL/revocation policy).
 *   2. Spawns `npm run buyer` and `npm run seller` in the
 *      `agents/` workspace as child processes, with the
 *      demo API key + backend URL injected via env.
 *   3. Tracks the PIDs and the spawned-at timestamp so
 *      the status endpoint can report the running pair.
 *
 * On stop, the orchestrator kills both children, revokes
 * the demo API key, and clears the state. The orchestrator
 * is also wired into the backend shutdown path (in
 * `server.ts`) so an operator `SIGTERM` cleans up the
 * children on the way out.
 *
 * The orchestrator is one-shot per process: a second
 * `startDemo()` call without a `stopDemo()` in between
 * throws. The route handler enforces this with a 409.
 */
export interface DemoAgentOrchestrator {
  startDemo(input: {
    institutionId: string;
    /** Plaintext API key to inject into the spawned agents. */
    demoApiKey: string;
    /**
     * ID of the API key the route handler minted for this
     * demo run. Stored in state and revoked on `stopDemo()`.
     * The orchestrator does NOT mint its own key — the route
     * handler owns the key lifecycle.
     */
    apiKeyId: string;
    /**
     * Pre-configured agent DID for the buyer process.
     * Passed through as `AGENT_IDENTITY_DID` so the agent
     * uses the same DID the backend configured with a VC.
     */
    buyerAgentDid?: string;
    /**
     * Pre-configured agent DID for the seller process.
     * Same pattern as buyerAgentDid.
     */
    sellerAgentDid?: string;
  }): Promise<DemoStatus>;
  stopDemo(): Promise<DemoStatus>;
  getStatus(): DemoStatus;
}

export interface DemoStatus {
  running: boolean;
  buyerPid?: number | undefined;
  sellerPid?: number | undefined;
  startedAt?: string | undefined;
  institutionId?: string | undefined;
  apiKeyId?: string | undefined;
  buyerLogTail?: string | undefined;
  sellerLogTail?: string | undefined;
}

interface InternalState {
  buyer?: ChildProcess;
  seller?: ChildProcess;
  startedAt: string;
  institutionId: string;
  apiKeyId: string;
  buyerLogTail: string;
  sellerLogTail: string;
}

const LOG_TAIL_BYTES = 4096;

export interface ChildProcessDemoAgentOrchestratorOptions {
  agentsDir: string;
  backendUrl: string;
  apiKeyService: ApiKeyManagementService;
  /**
   * The command + args prefix used to launch each side.
   * Defaults to `["npm", "run"]` so the production
   * orchestrator runs `npm run buyer` / `npm run seller`
   * from the `agents/` workspace. Tests override to
   * `["node"]` and pass `buyerScript` / `sellerScript`
   * (absolute paths) so the test doesn't need `npm` on
   * PATH.
   */
  runner?: readonly string[];
  /**
   * Absolute path to the buyer / seller entry scripts.
   * Defaults to `undefined`, which means the runner
   * expects an `npm run`-style invocation with the side
   * name as the next arg.
   */
  buyerScript?: string;
  sellerScript?: string;
}

export class ChildProcessDemoAgentOrchestrator implements DemoAgentOrchestrator {
  private state: InternalState | undefined;
  private readonly agentsDir: string;
  private readonly backendUrl: string;
  private readonly apiKeyService: ApiKeyManagementService;
  private readonly runner: readonly string[];
  private readonly buyerScript: string | undefined;
  private readonly sellerScript: string | undefined;

  public constructor(options: ChildProcessDemoAgentOrchestratorOptions) {
    this.agentsDir = resolve(options.agentsDir);
    this.backendUrl = options.backendUrl;
    this.apiKeyService = options.apiKeyService;
    this.runner = options.runner ?? ["npm", "run"];
    this.buyerScript = options.buyerScript;
    this.sellerScript = options.sellerScript;
  }

  public async startDemo(input: {
    institutionId: string;
    demoApiKey: string;
    apiKeyId: string;
    buyerAgentDid?: string;
    sellerAgentDid?: string;
  }): Promise<DemoStatus> {
    if (this.state) {
      throw new PublicError("service_unavailable", 409);
    }
    if (!input.demoApiKey.startsWith("gbk_")) {
      throw new PublicError("validation_failed", 400);
    }

    // The route handler owns the API key lifecycle: it mints
    // the key before calling startDemo and passes the id so
    // we can revoke it on stop. We do NOT mint our own key
    // here — that would leak an unused credential.

    // The agent DIDs are generated server-side by
    // `AgentService.configureAgent()` which also mints
    // and persists the delegation VC. We pass the DIDs
    // through to the spawned processes via
    // `AGENT_IDENTITY_DID` so the agent re-uses the same
    // DID the backend configured.
    const buyer = this.spawnSide("buyer", input.demoApiKey, input.buyerAgentDid);
    const seller = this.spawnSide("seller", input.demoApiKey, input.sellerAgentDid);

    const state: InternalState = {
      buyer,
      seller,
      startedAt: new Date().toISOString(),
      institutionId: input.institutionId,
      apiKeyId: input.apiKeyId,
      buyerLogTail: "",
      sellerLogTail: "",
    };

    this.tailStream(buyer, "buyer", state);
    this.tailStream(seller, "seller", state);
    this.state = state;

    return this.getStatus();
  }

  public async stopDemo(): Promise<DemoStatus> {
    if (!this.state) {
      return this.getStatus();
    }
    const { buyer, seller, apiKeyId, institutionId } = this.state;
    // Soft-kill first, hard-kill after 1s. npm wraps the
    // tsx child so the PID we hold is the npm process; the
    // SIGTERM propagates to the tsx child naturally. On
    // Windows the kill signal is the same — `tree-kill`
    // is overkill for the npm→tsx chain (npm already
    // spawns the child in the same process group on POSIX;
    // on Windows `taskkill /T` would be needed but the
    // tsx child exits when stdin closes, which happens
    // when the parent npm dies).
    if (buyer && buyer.exitCode === null) {
      buyer.kill("SIGTERM");
    }
    if (seller && seller.exitCode === null) {
      seller.kill("SIGTERM");
    }
    await new Promise((r) => setTimeout(r, 1_000));
    if (buyer && buyer.exitCode === null) {
      buyer.kill("SIGKILL");
    }
    if (seller && seller.exitCode === null) {
      seller.kill("SIGKILL");
    }
    // Revoke the demo API key so a leaked child stdout
    // capture can't be used to trade after the demo ends.
    try {
      await this.apiKeyService.revokeKey(apiKeyId, institutionId);
    } catch {
      // Revoke is best-effort; the TTL is the safety net
      // (the label + the post-demo sweep will catch any
      // orphan key on the next dashboard visit).
    }
    this.state = undefined;
    return this.getStatus();
  }

  public getStatus(): DemoStatus {
    if (!this.state) {
      return { running: false };
    }
    return {
      running: true,
      buyerPid: this.state.buyer?.pid,
      sellerPid: this.state.seller?.pid,
      startedAt: this.state.startedAt,
      institutionId: this.state.institutionId,
      apiKeyId: this.state.apiKeyId,
      buyerLogTail: this.state.buyerLogTail,
      sellerLogTail: this.state.sellerLogTail,
    };
  }

  /**
   * Build the `spawn()` argv + env for one side of the
   * demo. Two modes:
   *   - Default (`runner = ["npm", "run"]`): runs
   *     `npm run <side>` in the `agents/` workspace.
   *   - Test (`runner = ["node"]` + `buyerScript` /
   *     `sellerScript`): runs the script directly.
   * The env is built in `startDemo` and threaded through
   * unchanged.
   */
  private spawnSide(
    side: "buyer" | "seller",
    demoApiKey: string,
    agentDid?: string,
  ): ChildProcess {
    const isScriptMode =
      this.buyerScript !== undefined || this.sellerScript !== undefined;
    const script =
      side === "buyer" ? this.buyerScript : this.sellerScript;
    const env: NodeJS.ProcessEnv = {
      ...this.spawnEnv(demoApiKey),
      ...(agentDid ? { AGENT_IDENTITY_DID: agentDid } : {}),
    };
    const isWin = process.platform === "win32";
    const shell = isWin && this.runner[0] === "npm";

    if (isScriptMode && script) {
      return spawn(
        this.runner[0]!,
        [...this.runner.slice(1), script],
        {
          cwd: this.agentsDir,
          env,
          stdio: ["ignore", "pipe", "pipe"],
          shell,
        },
      );
    }
    return spawn(
      this.runner[0]!,
      [...this.runner.slice(1), side],
      {
        cwd: this.agentsDir,
        env,
        stdio: ["ignore", "pipe", "pipe"],
        shell,
      },
    );
  }

  private spawnEnv(demoApiKey: string): NodeJS.ProcessEnv {
    return {
      ...process.env,
      GHOSTBROKER_URL: this.backendUrl,
      GHOSTBROKER_API_KEY: demoApiKey,
      // The agents workspace reads GROQ_API_KEY from its
      // own `.env`; the orchestrator passes through the
      // host's env so the spawned processes pick it up
      // automatically. If the operator hasn't set it,
      // the buyer/seller preflight will fail with a clear
      // error pointing at the env var.
    };
  }

  private tailStream(
    proc: ChildProcess,
    side: "buyer" | "seller",
    state: InternalState,
  ): void {
    const append = (chunk: Buffer | string): void => {
      const text = chunk.toString("utf8");
      const key = side === "buyer" ? "buyerLogTail" : "sellerLogTail";
      const next = (state[key] + text).slice(-LOG_TAIL_BYTES);
      if (side === "buyer") {
        state.buyerLogTail = next;
      } else {
        state.sellerLogTail = next;
      }
    };
    proc.stdout?.on("data", append);
    proc.stderr?.on("data", append);
  }
}

import {
  type TenantDidRegistry,
  rotateEnvelopeKey,
  createEnvelopeKeyMetadata,
} from "@ghostbroker/t3-enclave";
import { PublicError } from "../errors/public-error.js";
import {
  institutionFromRecord,
  type CreateInstitutionRequest,
  type Institution,
  type InstitutionRecord,
} from "../models/institution.js";

interface InsertQuery<TResult> {
  insert(value: Record<string, unknown>): {
    select(columns?: string): {
      single(): Promise<{ data: TResult | null; error: Error | null }>;
    };
  };
}

interface SelectQuery<TResult> {
  select(columns?: string): {
    eq(column: string, value: string): {
      maybeSingle(): Promise<{ data: TResult | null; error: Error | null }>;
      single(): Promise<{ data: TResult | null; error: Error | null }>;
    };
  };
}

interface UpdateQuery<TResult> {
  update(value: Record<string, unknown>): {
    eq(column: string, value: string): {
      select(columns?: string): {
        single(): Promise<{ data: TResult | null; error: Error | null }>;
      };
    };
  };
}

export interface InstitutionRepository {
  createInstitution(value: {
    legalName: string;
    displayName: string;
    settlementProfileRef: string;
    t3TenantDid: string;
    metadata: Readonly<Record<string, unknown>>;
  }): Promise<Institution>;
  findByTenantDid(did: string): Promise<Institution | null>;
  findById(id: string): Promise<Institution | null>;
  updateMetadata?(id: string, metadata: Readonly<Record<string, unknown>>): Promise<Institution>;
}

export interface InstitutionManagementService {
  createInstitution(request: CreateInstitutionRequest): Promise<Institution>;
  getInstitution?(id: string): Promise<Institution>;
  rotateKeys?(id: string): Promise<Institution>;
}

export interface SupabaseInstitutionClient {
  from(table: "institutions"): InsertQuery<InstitutionRecord> &
    SelectQuery<InstitutionRecord> &
    UpdateQuery<InstitutionRecord>;
}

export class SupabaseInstitutionRepository implements InstitutionRepository {
  private readonly client: SupabaseInstitutionClient;

  public constructor(client: SupabaseInstitutionClient) {
    this.client = client;
  }

  public async createInstitution(value: {
    legalName: string;
    displayName: string;
    settlementProfileRef: string;
    t3TenantDid: string;
    metadata: Readonly<Record<string, unknown>>;
  }): Promise<Institution> {
    const { data, error } = await this.client
      .from("institutions")
      .insert({
        legal_name: value.legalName,
        display_name: value.displayName,
        status: "active",
        t3_tenant_did: value.t3TenantDid,
        settlement_profile_ref: value.settlementProfileRef,
        metadata: value.metadata,
      })
      .select("*")
      .single();

    if (error || !data) {
      throw new PublicError("service_unavailable", 503, error);
    }

    return institutionFromRecord(data);
  }

  public async findByTenantDid(did: string): Promise<Institution | null> {
    const { data, error } = await this.client
      .from("institutions")
      .select("*")
      .eq("t3_tenant_did", did)
      .maybeSingle();

    if (error) {
      throw new PublicError("service_unavailable", 503, error);
    }

    return data ? institutionFromRecord(data) : null;
  }

  public async findById(id: string): Promise<Institution | null> {
    const { data, error } = await this.client
      .from("institutions")
      .select("*")
      .eq("id", id)
      .maybeSingle();

    if (error) {
      throw new PublicError("service_unavailable", 503, error);
    }

    return data ? institutionFromRecord(data) : null;
  }

  public async updateMetadata(
    id: string,
    metadata: Readonly<Record<string, unknown>>,
  ): Promise<Institution> {
    const { data, error } = await this.client
      .from("institutions")
      .update({ metadata })
      .eq("id", id)
      .select("*")
      .single();

    if (error || !data) {
      throw new PublicError("service_unavailable", 503, error);
    }

    return institutionFromRecord(data);
  }
}

export class InstitutionService implements InstitutionManagementService {
  private readonly repository: InstitutionRepository;
  private readonly didRegistry: TenantDidRegistry;

  public constructor(
    repository: InstitutionRepository,
    didRegistry: TenantDidRegistry,
  ) {
    this.repository = repository;
    this.didRegistry = didRegistry;
  }

  public async createInstitution(
    request: CreateInstitutionRequest,
  ): Promise<Institution> {
    const tenant = await this.didRegistry.resolveOrRegisterTenantDid({
      legalName: request.legalName,
      displayName: request.displayName,
      settlementProfileRef: request.settlementProfileRef,
    });

    return this.repository.createInstitution({
      legalName: request.legalName,
      displayName: request.displayName,
      settlementProfileRef: request.settlementProfileRef,
      t3TenantDid: tenant.tenantDid,
      metadata: request.metadata ?? {},
    });
  }

  public async getInstitution(id: string): Promise<Institution> {
    const institution = await this.repository.findById(id);
    if (!institution) {
      throw new PublicError("not_found", 404, "Institution not found");
    }
    return institution;
  }

  public async rotateKeys(id: string): Promise<Institution> {
    const institution = await this.repository.findById(id);
    if (!institution) {
      throw new PublicError("not_found", 404, "Institution not found");
    }

    const currentMetadata = (institution.metadata || {}) as Record<string, any>;
    const currentKeys = currentMetadata.envelopeKeys || {};

    const nextKeys: Record<string, any> = {};

    // 1. Rotate/generate hidden_intent key
    const prevIntent = currentKeys.hidden_intent?.keyVersion;
    let newIntentKey;
    if (prevIntent) {
      newIntentKey = rotateEnvelopeKey({
        institutionDid: institution.t3TenantDid,
        purpose: "hidden_intent",
        previousKeyVersion: prevIntent,
      });
    } else {
      newIntentKey = {
        current: createEnvelopeKeyMetadata({
          institutionDid: institution.t3TenantDid,
          purpose: "hidden_intent",
        }),
        rotatedAt: new Date().toISOString(),
      };
    }
    nextKeys.hidden_intent = {
      keyVersion: newIntentKey.current.keyVersion,
      publicKeyRef: newIntentKey.current.publicKeyRef,
      createdAt: newIntentKey.rotatedAt,
    };

    // 2. Rotate/generate receipt key
    const prevReceipt = currentKeys.receipt?.keyVersion;
    let newReceiptKey;
    if (prevReceipt) {
      newReceiptKey = rotateEnvelopeKey({
        institutionDid: institution.t3TenantDid,
        purpose: "receipt",
        previousKeyVersion: prevReceipt,
      });
    } else {
      newReceiptKey = {
        current: createEnvelopeKeyMetadata({
          institutionDid: institution.t3TenantDid,
          purpose: "receipt",
        }),
        rotatedAt: new Date().toISOString(),
      };
    }
    nextKeys.receipt = {
      keyVersion: newReceiptKey.current.keyVersion,
      publicKeyRef: newReceiptKey.current.publicKeyRef,
      createdAt: newReceiptKey.rotatedAt,
    };

    const nextMetadata = {
      ...currentMetadata,
      envelopeKeys: nextKeys,
    };

    return this.repository.updateMetadata!(id, nextMetadata);
  }
}

import { issueOperatorSessionToken } from "./auth/session-token.js";
import { loadEnv } from "./config/env.js";

async function main() {
  const env = loadEnv();
  const institutionId = "ec27760a-bec2-4924-b7c3-7e358547bf83";
  const token = issueOperatorSessionToken({
    secret: env.AUTH_SESSION_SECRET ?? "",
    did: "did:t3n:operator:dev",
    institutionId,
  });

  console.log("Starting demo...");
  const startRes = await fetch("http://localhost:3001/api/demo/start", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${token}`,
    },
    body: JSON.stringify({ institutionId }),
  });

  if (!startRes.ok) {
    const text = await startRes.text();
    console.error(`Failed to start demo: ${startRes.status} ${text}`);
    return;
  }

  const startData = await startRes.json();
  console.log("Demo started:", startData);

  console.log("Waiting 15 seconds for agents to run and log their activity...");
  await new Promise((r) => setTimeout(r, 15000));

  console.log("Querying demo status...");
  const statusRes = await fetch("http://localhost:3001/api/demo/status", {
    method: "GET",
    headers: {
      "Authorization": `Bearer ${token}`,
    },
  });

  if (!statusRes.ok) {
    console.error("Failed to get demo status");
  } else {
    const statusData = (await statusRes.json()) as any;
    console.log("Demo status:", JSON.stringify(statusData, null, 2));
    console.log("=== BUYER LOGS ===");
    console.log(statusData.buyerLogTail);
    console.log("=== SELLER LOGS ===");
    console.log(statusData.sellerLogTail);
  }

  console.log("Stopping demo...");
  const stopRes = await fetch("http://localhost:3001/api/demo/stop", {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${token}`,
    },
  });
  console.log("Demo stopped:", await stopRes.json());
}

main().catch(console.error);

