export type RedactedErrorCode =
  | 'authorization_failed'
  | 'validation_failed'
  | 'service_unavailable'
  | 'not_found';

export interface RedactedError {
  code: RedactedErrorCode;
  message: string;
}

export class ApiClientError extends Error {
  status: number;
  code: RedactedErrorCode | 'request_failed';

  constructor(status: number, code: RedactedErrorCode | 'request_failed', message: string) {
    super(message);
    this.name = 'ApiClientError';
    this.status = status;
    this.code = code;
    // Maintains proper stack trace for where our error was thrown (only available on V8)
    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, ApiClientError);
    }
  }
}

const API_BASE_URL = (import.meta.env.VITE_API_BASE_URL || 'http://localhost:3001').replace(/\/$/, '');

const AUTH_TOKEN_KEY = 'ghostbroker-auth-token';
const AUTH_SESSION_KEY = 'ghostbroker-auth-session';

const getOperatorHeaders = (): Record<string, string> => {
  const token = localStorage.getItem(AUTH_TOKEN_KEY);
  if (token) {
    return {
      Authorization: `Bearer ${token}`,
    };
  }

  // No valid bearer token available. Sending the operator identity headers
  // without a real signed JWT would always result in a 401 from the backend.
  // Return an empty header map so the request fails fast with a clear,
  // unauthenticated error instead of looping on a stale token.
  return {};
};

function buildOperatorRequestInit(init: RequestInit = {}): RequestInit {
  const headers: Record<string, string> = {};

  if (init.headers) {
    if (init.headers instanceof Headers) {
      init.headers.forEach((value, key) => {
        headers[key] = value;
      });
    } else if (Array.isArray(init.headers)) {
      init.headers.forEach(([key, value]) => {
        headers[key] = value;
      });
    } else {
      Object.assign(headers, init.headers);
    }
  }

  headers['Accept'] = headers['Accept'] ?? 'application/json';

  for (const [key, value] of Object.entries(getOperatorHeaders())) {
    headers[key] = value;
  }

  return {
    ...init,
    headers,
  };
}

async function requestWithOperatorFallback(
  input: string,
  init: RequestInit = {},
): Promise<Response> {
  const performFetch = () => fetch(input, buildOperatorRequestInit(init));
  let response = await performFetch();

  if (response.status === 401 && localStorage.getItem(AUTH_TOKEN_KEY)) {
    apiClient.clearAuthSession();
    response = await performFetch();
  }

  return response;
}

async function handleResponse<T>(response: Response): Promise<T> {
  if (!response.ok) {
    let errorCode: RedactedErrorCode | 'request_failed' = 'request_failed';
    let errorMessage = `HTTP error! Status: ${response.status}`;

    try {
      const errorData = await response.json() as Partial<RedactedError>;
      if (errorData && typeof errorData.code === 'string') {
        errorCode = errorData.code as RedactedErrorCode;
      }
      if (errorData && typeof errorData.message === 'string') {
        errorMessage = errorData.message;
      }
    } catch {
      // Body is not JSON, fallback to generic messages based on status
      if (response.status === 403) {
        errorCode = 'authorization_failed';
        errorMessage = 'Authorization failed. Request rejected by the security enclave.';
      } else if (response.status === 404) {
        errorCode = 'not_found';
        errorMessage = 'Requested resource was not found.';
      } else if (response.status >= 500) {
        errorCode = 'service_unavailable';
        errorMessage = 'The secure enclave services are temporarily unavailable.';
      }
    }

    throw new ApiClientError(response.status, errorCode, errorMessage);
  }

  return response.json() as Promise<T>;
}

export const apiClient = {
  setAuthSession(session: AuthSession): void {
    localStorage.setItem(AUTH_TOKEN_KEY, session.token);
    localStorage.setItem(AUTH_SESSION_KEY, JSON.stringify(session));
    localStorage.setItem('x-operator-institution-id', session.institution.id);
    localStorage.setItem('x-operator-id', `did:${session.institution.t3TenantDid}`);
  },

  clearAuthSession(): void {
    localStorage.removeItem(AUTH_TOKEN_KEY);
    localStorage.removeItem(AUTH_SESSION_KEY);
  },

  getAuthSession(): AuthSession | null {
    const raw = localStorage.getItem(AUTH_SESSION_KEY);
    if (raw) {
      try {
        const session = JSON.parse(raw) as AuthSession;
        if (new Date(session.expiresAt).getTime() <= Date.now()) {
          this.clearAuthSession();
        } else {
          return session;
        }
      } catch {
        this.clearAuthSession();
      }
    }

    // No valid session. Never fabricate a synthetic session with a fake
    // `e2e-bypass-token` — the backend has no way to validate it and every
    // authenticated request would fail with 401. Callers must use the real
    // DID challenge/verify flow (wallet auth) to obtain a signed JWT.
    return null;
  },

  setOperatorContext(institutionId: string, operatorId?: string): void {
    localStorage.setItem('x-operator-institution-id', institutionId);
    if (operatorId) {
      localStorage.setItem('x-operator-id', operatorId);
    } else {
      localStorage.removeItem('x-operator-id');
    }
  },

  getOperatorContext(): { institutionId: string; operatorId: string } {
    return {
      institutionId: localStorage.getItem('x-operator-institution-id') || '00000000-0000-4000-8000-000000000301',
      operatorId: localStorage.getItem('x-operator-id') || 'operator:unattributed',
    };
  },

  async getHealth(): Promise<HealthResponse> {
    const res = await fetch(`${API_BASE_URL}/api/health`, {
      headers: {
        'Accept': 'application/json',
      },
    });
    return handleResponse<HealthResponse>(res);
  },

  async createInstitution(req: CreateInstitutionRequest): Promise<Institution> {
    const res = await fetch(`${API_BASE_URL}/api/institutions`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
      },
      body: JSON.stringify(req),
    });
    return handleResponse<Institution>(res);
  },

  async getInstitution(id: string): Promise<Institution> {
    const res = await requestWithOperatorFallback(`${API_BASE_URL}/api/institutions/${id}`);
    return handleResponse<Institution>(res);
  },

  async rotateKeys(id: string): Promise<Institution> {
    const res = await requestWithOperatorFallback(
      `${API_BASE_URL}/api/institutions/${id}/rotate-key`,
      { method: 'POST' },
    );
    return handleResponse<Institution>(res);
  },

  async requestAuthChallenge(did: string): Promise<AuthChallenge> {
    const res = await fetch(`${API_BASE_URL}/api/auth/challenge`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
      },
      body: JSON.stringify({ did }),
    });
    return handleResponse<AuthChallenge>(res);
  },

  async verifyAuthChallenge(req: {
    challengeId: string;
    did: string;
    signature: string;
    walletAddress?: string;
  }): Promise<AuthSession> {
    const res = await fetch(`${API_BASE_URL}/api/auth/verify`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
      },
      body: JSON.stringify(req),
    });
    const session = await handleResponse<AuthSession>(res);
    this.setAuthSession(session);
    return session;
  },

  async admitAgent(req: AdmitAgentRequest): Promise<AgentAdmission> {
    const res = await requestWithOperatorFallback(`${API_BASE_URL}/api/agents/admit`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(req),
    });
    return handleResponse<AgentAdmission>(res);
  },

  async submitIntent(req: EncryptedIntentRequest): Promise<IntentAccepted> {
    const res = await requestWithOperatorFallback(`${API_BASE_URL}/api/agents/intents`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(req),
    });
    return handleResponse<IntentAccepted>(res);
  },

  async getCompletedTrades(from?: string, to?: string): Promise<{ items: CompletedTrade[] }> {
    const url = new URL(`${API_BASE_URL}/api/trades/completed`);
    if (from) url.searchParams.append('from', from);
    if (to) url.searchParams.append('to', to);

    const res = await requestWithOperatorFallback(url.toString(), {
      headers: {},
    });
    return handleResponse<{ items: CompletedTrade[] }>(res);
  },

  async getPortfolio(institutionId: string): Promise<Portfolio> {
    const res = await requestWithOperatorFallback(
      `${API_BASE_URL}/api/portfolios/${institutionId}`,
    );
    return handleResponse<Portfolio>(res);
  },

  async getPortfolioHistory(
    institutionId: string,
    limit = 50,
  ): Promise<PortfolioHistoryEntry[]> {
    const url = new URL(`${API_BASE_URL}/api/portfolios/${institutionId}/history`);
    if (limit !== undefined) {
      url.searchParams.set('limit', String(limit));
    }

    const res = await requestWithOperatorFallback(url.toString());
    return handleResponse<PortfolioHistoryEntry[]>(res);
  },

  async getReceipt(receiptId: string): Promise<AuditReceipt> {
    const res = await requestWithOperatorFallback(`${API_BASE_URL}/api/receipts/${receiptId}`);
    return handleResponse<AuditReceipt>(res);
  },

  // ── Agent Management ──────────────────────────────────────────────────

  async listAgents(status?: "admitted" | "revoked"): Promise<Agent[]> {
    const url = new URL(`${API_BASE_URL}/api/agents`);
    if (status) url.searchParams.append("status", status);

    const res = await requestWithOperatorFallback(url.toString());
    return handleResponse<Agent[]>(res);
  },

  async getAgent(id: string): Promise<Agent> {
    const res = await requestWithOperatorFallback(
      `${API_BASE_URL}/api/agents/${id}`,
    );
    return handleResponse<Agent>(res);
  },

  async updateAgentLabel(id: string, label: string): Promise<Agent> {
    const res = await requestWithOperatorFallback(
      `${API_BASE_URL}/api/agents/${id}`,
      {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ label }),
      },
    );
    return handleResponse<Agent>(res);
  },

  async revokeAgent(id: string): Promise<void> {
    await requestWithOperatorFallback(
      `${API_BASE_URL}/api/agents/${id}/revoke`,
      { method: "POST" },
    );
  },

  async mintDelegation(
    id: string,
    policy: {
      maxSpendUsd: number;
      allowedCategories: string[];
      approverEmail?: string;
      purpose?: string;
      validityMonths?: number;
    },
  ): Promise<{ authorityRef: string; policyHash: string }> {
    const res = await requestWithOperatorFallback(
      `${API_BASE_URL}/api/agents/${id}/delegation`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(policy),
      },
    );
    return handleResponse<{ authorityRef: string; policyHash: string }>(res);
  },

  // ── API Key Management ────────────────────────────────────────────────

  async listApiKeys(): Promise<ApiKey[]> {
    const res = await requestWithOperatorFallback(
      `${API_BASE_URL}/api/keys`,
    );
    return handleResponse<ApiKey[]>(res);
  },

  async createApiKey(label: string, scopes?: string[]): Promise<CreatedApiKey> {
    const res = await requestWithOperatorFallback(
      `${API_BASE_URL}/api/keys`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ label, scopes: scopes ?? ['agent:operate'] }),
      },
    );
    return handleResponse<CreatedApiKey>(res);
  },

  async revokeApiKey(id: string): Promise<void> {
    await requestWithOperatorFallback(
      `${API_BASE_URL}/api/keys/${id}/revoke`,
      { method: 'POST' },
    );
  },

  // ── Phase 2.5: Demo Mode ───────────────────────────────────
  //
  // The dashboard's Observatory tab calls these three
  // methods to drive the one-click "Spin up demo agents"
  // button. The backend spawns a buyer + seller agent as
  // child processes, authenticated with a per-run API key
  // minted at start time and revoked on stop.

  async startDemo(institutionId: string): Promise<DemoStatus> {
    const res = await requestWithOperatorFallback(
      `${API_BASE_URL}/api/demo/start`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ institutionId }),
      },
    );
    return handleResponse<DemoStatus>(res);
  },

  async stopDemo(): Promise<DemoStatus> {
    const res = await requestWithOperatorFallback(
      `${API_BASE_URL}/api/demo/stop`,
      { method: 'POST' },
    );
    return handleResponse<DemoStatus>(res);
  },

  async getDemoStatus(): Promise<DemoStatus> {
    const res = await requestWithOperatorFallback(
      `${API_BASE_URL}/api/demo/status`,
      { method: 'GET' },
    );
    return handleResponse<DemoStatus>(res);
  },
};

import { AccountId, Client, PrivateKey } from "@hashgraph/sdk";
import { hederaT3nPlugin } from "@terminal3/hedera-t3n-plugin";
import { AgentMode, HederaLangchainToolkit } from "hedera-agent-kit";
import type { AgentIdentity } from "../types.js";
import { isLiveMode } from "./mode.js";

export interface PrivateFieldCheckResult {
  available: boolean;
  fieldExistence?: Record<string, boolean>;
  missingFields?: string[];
  unsupportedFields?: string[];
  guidance?: string;
  error?: string;
  authReady?: boolean;
}

interface PrivateDataProcessingRaw {
  success?: boolean;
  error?: string;
  userDid?: string;
  fieldExistence?: Record<string, boolean>;
  missingFields?: string[];
  unsupportedFields?: Array<{ field: string; reason: string }>;
  guidance?: {
    profileUrl?: string | null;
    onboardingUrl?: string | null;
    steps?: string[];
  };
  authReady?: boolean;
  authError?: string;
}

function buildHederaClient(): Client {
  const network = process.env.HEDERA_NETWORK ?? "testnet";
  const accountId = process.env.HEDERA_ACCOUNT_ID;
  const privateKeyHex = process.env.HEDERA_PRIVATE_KEY;

  if (!accountId || !privateKeyHex) {
    throw new Error("HEDERA_ACCOUNT_ID and HEDERA_PRIVATE_KEY are required");
  }

  const client =
    network === "mainnet"
      ? Client.forMainnet()
      : network === "local"
        ? Client.forNetwork({ "127.0.0.1:50211": "0.0.3" })
        : Client.forTestnet();

  const operatorId = AccountId.fromString(accountId);
  const operatorKey = PrivateKey.fromStringECDSA(privateKeyHex);
  client.setOperator(operatorId, operatorKey);
  return client;
}

function formatGuidance(raw: PrivateDataProcessingRaw): string | undefined {
  const steps = raw.guidance?.steps ?? [];
  const urls = [
    raw.guidance?.profileUrl,
    raw.guidance?.onboardingUrl,
  ].filter(Boolean);

  const parts = [...steps, ...urls.map((url) => String(url))];
  return parts.length > 0 ? parts.join(" | ") : undefined;
}

/**
 * Bridge to Terminal 3's Hedera plugin for PRIVATE_DATA_PROCESSING.
 * Falls back gracefully in sandbox mode.
 */
export class T3PluginBridge {
  constructor(private readonly identity: AgentIdentity) {}

  get isLive(): boolean {
    return (
      isLiveMode() &&
      this.identity.registered &&
      Boolean(process.env.AGENT_IDENTITY_CONFIG_PATH) &&
      Boolean(process.env.HEDERA_ACCOUNT_ID) &&
      !process.env.HEDERA_ACCOUNT_ID?.includes("xxxxx")
    );
  }

  async verifyUserProfileFields(
    userDid: string,
    fields: string[],
  ): Promise<PrivateFieldCheckResult> {
    if (!this.isLive) {
      return {
        available: false,
        guidance:
          "T3 live mode unavailable. Set T3_MODE=live, register the agent, and configure Hedera credentials.",
      };
    }

    try {
      const client = buildHederaClient();
      const toolkit = new HederaLangchainToolkit({
        client: client as never,
        configuration: {
          plugins: [hederaT3nPlugin],
          context: {
            accountId: process.env.HEDERA_ACCOUNT_ID,
            mode: AgentMode.AUTONOMOUS,
          },
        },
      });

      const api = toolkit.getHederaAgentKitAPI();
      const output = await api.run("private_data_processing", {
        userDid,
        fields,
      });

      const parsed = JSON.parse(output) as {
        raw?: PrivateDataProcessingRaw;
        humanMessage?: string;
      };
      const raw = parsed.raw ?? (parsed as PrivateDataProcessingRaw);

      if (!raw.success) {
        return {
          available: false,
          error: raw.error ?? raw.authError ?? "PRIVATE_DATA_PROCESSING_FAILED",
          fieldExistence: raw.fieldExistence,
          missingFields: raw.missingFields,
          unsupportedFields: raw.unsupportedFields?.map((entry) => entry.field),
          guidance: formatGuidance(raw) ?? parsed.humanMessage,
          authReady: raw.authReady,
        };
      }

      return {
        available: true,
        fieldExistence: raw.fieldExistence,
        missingFields: raw.missingFields,
        unsupportedFields: raw.unsupportedFields?.map((entry) => entry.field),
        guidance: formatGuidance(raw) ?? parsed.humanMessage,
        authReady: raw.authReady,
      };
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "Unknown T3 plugin error";
      return {
        available: false,
        error: message,
        guidance: `T3 plugin call failed: ${message}`,
      };
    }
  }
}

import type { DelegationCredential, PolicyResult, PurchaseRequest } from "../types.js";
import { PolicyEngine } from "../auth/policy-engine.js";
import { isLiveMode } from "./mode.js";
import { getPersistedSpendUsd, persistSpendUsd, getTenantClient } from "./adk-client.js";

export type PolicySource = "tee" | "local";

export interface PolicyEvaluation extends PolicyResult {
  policySource: PolicySource;
}

interface TeePolicyInput {
  delegation_id: string;
  max_spend_usd: number;
  allowed_categories: string[];
  purchase_category: string;
  purchase_total_usd: number;
  agent_did: string;
  authorized_agent_did: string;
  in_stock: boolean;
}

interface TeePolicyOutputWire {
  decision: "approved" | "denied";
  reasons: string[];
  remaining_budget_usd: number;
  spent_usd: number;
}

function isTeePolicyConfigured(): boolean {
  return Boolean(
    process.env.T3_POLICY_CONTRACT_NAME &&
      process.env.T3N_API_KEY &&
      isLiveMode(),
  );
}

async function evaluateInTee(input: TeePolicyInput): Promise<{
  decision: "approved" | "denied";
  reasons: string[];
  remainingBudgetUsd: number;
  spentUsd: number;
}> {
  const client = await getTenantClient();
  const contractTail = process.env.T3_POLICY_CONTRACT_NAME!;

  const wire = (await client.contracts.execute(contractTail, {
    version: process.env.T3_POLICY_CONTRACT_VERSION ?? "0.1.0",
    functionName: "evaluate-purchase",
    input,
  })) as TeePolicyOutputWire;

  return {
    decision: wire.decision,
    reasons: wire.reasons,
    remainingBudgetUsd: wire.remaining_budget_usd,
    spentUsd: wire.spent_usd,
  };
}

export class PolicyEvaluator {
  private readonly localEngine: PolicyEngine;
  private spentUsd = 0;

  constructor(
    private readonly delegation: DelegationCredential,
    initialSpentUsd = 0,
  ) {
    this.localEngine = new PolicyEngine(delegation);
    this.spentUsd = initialSpentUsd;
    if (initialSpentUsd > 0) {
      this.localEngine.commitSpend(initialSpentUsd);
    }
  }

  static async create(
    delegation: DelegationCredential,
  ): Promise<PolicyEvaluator> {
    const spent = isLiveMode()
      ? await getPersistedSpendUsd(delegation.id)
      : 0;
    return new PolicyEvaluator(delegation, spent);
  }

  get remainingBudgetUsd(): number {
    return this.localEngine.remainingBudgetUsd;
  }

  async evaluate(
    request: PurchaseRequest,
    agentDid: string,
  ): Promise<PolicyEvaluation> {
    if (isTeePolicyConfigured()) {
      try {
        const teeResult = await evaluateInTee({
          delegation_id: this.delegation.id,
          max_spend_usd: this.delegation.credentialSubject.maxSpendUsd,
          allowed_categories: this.delegation.credentialSubject.allowedCategories,
          purchase_category: request.quote.category,
          purchase_total_usd: request.quote.totalUsd,
          agent_did: agentDid,
          authorized_agent_did: this.delegation.credentialSubject.agentDid,
          in_stock: request.quote.inStock,
        });

        this.spentUsd = teeResult.spentUsd;
        await persistSpendUsd(this.delegation.id, this.spentUsd);

        return {
          decision: teeResult.decision,
          reasons: teeResult.reasons,
          remainingBudgetUsd: teeResult.remainingBudgetUsd,
          policySource: "tee",
        };
      } catch (error) {
        const message =
          error instanceof Error ? error.message : "TEE policy evaluation failed";
        console.warn(`[policy] TEE fallback to local engine: ${message}`);
      }
    }

    const local = this.localEngine.evaluate(request, agentDid);
    return { ...local, policySource: "local" };
  }

  async commitSpend(amountUsd: number): Promise<void> {
    this.spentUsd += amountUsd;
    this.localEngine.commitSpend(amountUsd);
    await persistSpendUsd(this.delegation.id, this.spentUsd);
  }
}

import { test, expect } from '@playwright/test';
import { 
  clearDatabase, 
  seedInstitutions, 
  seedCompletedTradeAndReceipt,
  us3UnrelatedInstitutionId,
  us3BuyerInstitutionId,
  us3ReceiptId
} from './support/local-stack';
import { assertNoPrivacyLeaks } from './support/privacy-assertions';

const API_BASE_URL = process.env.PLAYWRIGHT_API_BASE_URL || 'http://localhost:3001';

async function setAuthContext(page: any, pwRequest: any, institutionId: string, operatorId: string) {
  const tokenRes = await pwRequest.post(`${API_BASE_URL}/api/dev/token`, {
    data: { institutionId },
  });
  const { token } = await tokenRes.json();
  await page.evaluate(({ instId, opId, authToken }) => {
    localStorage.setItem('x-operator-institution-id', instId);
    localStorage.setItem('x-operator-id', opId);
    localStorage.setItem('ghostbroker-auth-token', authToken);
  }, { instId: institutionId, opId: operatorId, authToken: token });
}

test.describe('Dashboard Privacy Guardrails', () => {
  test.beforeEach(async ({ page }) => {
    // Reset and seed database
    await clearDatabase();
    await seedInstitutions();
    await seedCompletedTradeAndReceipt();
  });

  test('should hide trades from unrelated institution and prevent privacy leaks', async ({ page, request: pwRequest }) => {
    // Set operator to Unrelated Institution
    await page.goto('/');
    await setAuthContext(page, pwRequest, us3UnrelatedInstitutionId, 'operator:e2e-unrelated');

    await page.reload();

    // Verify empty state is shown (since the trade is only for buyer & seller)
    await expect(page.locator('text=No completed trades recorded')).toBeVisible();
    await expect(page.locator('text=match_outcome_us3')).not.toBeVisible();

    // Verify no privacy leaks of active order terms or plaintext properties
    await assertNoPrivacyLeaks(page);
  });

  test('should deny receipt decryption for unrelated institution and render safe error', async ({ page, request: pwRequest }) => {
    // 1. Authenticate as Buyer first to open the receipt drawer
    await page.goto('/');
    await setAuthContext(page, pwRequest, us3BuyerInstitutionId, 'operator:e2e-buyer');
    await page.reload();

    // Open receipt drawer
    const auditBtn = page.locator('button:has-text("Audit Receipt")');
    await expect(auditBtn).toBeVisible();
    await auditBtn.dispatchEvent('click');
    await expect(page.getByTestId('receipt-drawer')).toBeVisible();

    // 2. Change operator context in localStorage to unrelated institution
    await setAuthContext(page, pwRequest, us3UnrelatedInstitutionId, 'operator:e2e-unrelated');

    // 3. Directly load/request the receipt endpoint as the unrelated operator
    // Since the drawer is open, a reload will trigger a fetch using the new credentials
    await page.reload();

    // Drawer should show the secure decryption authorization error
    await expect(page.locator('text=Decryption Authorization Failed')).toBeVisible();
    await expect(page.locator('text=Verification failed. The operator does not hold keys to decrypt this receipt.')).toBeVisible();
    await expect(page.locator('text=t3receipt.buyer.ciphertext')).not.toBeVisible();

    // Double check privacy leaks
    await assertNoPrivacyLeaks(page);
  });
});
